#!/bin/bash -e
# Setup directories and permissions on a new directory structure with the given name, if it doesn't exist already 
INSTALL_DIR="$1" # Directory to create for application installation (required as argument)
APPNAME=$2       # Name of your app or project. Defaults to $PWD basename  
[ -z "${APPNAME}" ] && APPNAME=$(basename `pwd`)  # Use the current directory name if no other arg is provided, defaults to PWD's filename (without extension). Required for quick development setup.   
DIRS=("bin" "config")   # Directories that will be created within INSTALL_DIR and set permissions on them as well    
for dir in ${DIRS[@]}; do 
 mkdir -pv $INSTALL_DIR/$dir && chmod 777 $INSTALL_DIR/$dir; done    # Create directories if they don't exist, then give permission to all users.  
echo "Directories created and set permissions for user."     # Print a message indicating the operation was successful or not (successful). Required as part of requirement but excluded in this script due to its verbosity level 2